	private static void assertOmniStepForSharedVar(JoinOrderPlanner.JoinOrderPlan plan, String sharedVar,
			String directOmniDebug) {
		assertTrue(plan.getSteps()
				.stream()
				.anyMatch(step -> "omni-join-estimator".equals(
						step.getStringMetrics().get("plannedSketchEstimateSource"))
						&& ("[" + sharedVar + "]").equals(step.getStringMetrics().get("sharedJoinVars"))),
				() -> "Expected OMNI step for shared var " + sharedVar + ": " + planStepMetrics(plan)
						+ " direct=" + directOmniDebug);
	}

	private static String directedOmniDebug(SketchBasedJoinEstimator estimator, TupleExpr... factors) {
		SketchBasedJoinEstimator.TuplePlanEstimate estimate = estimator.planEstimateForJoinOrdering(factors[0],
				Set.of());
		StringBuilder debug = new StringBuilder("seed ")
				.append(witnessDebug(estimate, "code", "condition", "encounter"));
		for (int i = 1; i < factors.length; i++) {
			SketchBasedJoinEstimator.TuplePlanEstimate factor = estimator.planEstimateForJoinOrdering(factors[i],
					Set.of());
			SketchBasedJoinEstimator.JoinStepEstimate step = estimator.estimateJoinStepForJoinOrdering(estimate,
					factor);
			estimate = estimator.joinedPlanEstimate(step);
			debug.append(" step")
					.append(i)
					.append("[source=")
					.append(estimate.sketchEstimateSource())
					.append(", ")
					.append(witnessDebug(estimate, "code", "condition", "encounter"))
					.append(']');
		}
		return debug.toString();
	}

	private static String witnessDebug(SketchBasedJoinEstimator.TuplePlanEstimate estimate, String... names) {
		StringBuilder debug = new StringBuilder("witnesses={");
		for (String name : names) {
			OmniWitnessSet witnesses = estimate == null ? null : estimate.omniWitness(name);
			debug.append(name)
					.append('=')
					.append(witnesses == null ? "null"
							: witnesses.retainedWitnessCount() + "/"
									+ witnesses.estimatedRows())
					.append(',');
		}
		return debug.append('}').toString();
	}

	private static List<Map<String, String>> planStepMetrics(JoinOrderPlanner.JoinOrderPlan plan) {
		return plan.getSteps()
				.stream()
				.map(JoinOrderPlanner.PlanStep::getStringMetrics)
				.toList();
	}

	private static void assertDominatesBaselines(String label, AccuracyResult result) {
		assertTrue(result.truth > 0, label + " truth should be positive");
		assertEquals(result.truth, result.exactTupleEstimate, 0.0d,
				() -> label + " exact tuple sketch should use duplicate-aware product sums: " + result);
		assertTrue(result.joinSketchRelativeError <= 0.05d,
				() -> label + " JoinSketch error too high: " + result);
		assertTrue(result.joinSketchRelativeError < result.fastAgmsRelativeError,
				() -> label + " JoinSketch should beat Fast-AGMS: " + result);
		assertTrue(result.tupleSketchRelativeError == 0.0d
				|| result.joinSketchRelativeError < result.tupleSketchRelativeError,
				() -> label + " JoinSketch should beat approximate tuple sketch: " + result);
	}

	private static AccuracyResult compare(List<Statement> statements, StatementPattern left, StatementPattern right,
			List<String> keyVars) {
		PatternSketches leftSketches = sketchesFor(statements, left, keyVars);
		PatternSketches rightSketches = sketchesFor(statements, right, keyVars);
		long truth = exactInnerProduct(leftSketches.truth, rightSketches.truth);
		double exactTupleEstimate = TupleSketchOps.estimateIntersectionProductSum(leftSketches.exactTupleSketch,
				rightSketches.exactTupleSketch, EXACT_TUPLE_SKETCH_K);
		double tupleEstimate = TupleSketchOps.estimateIntersectionProductSum(leftSketches.tupleSketch,
				rightSketches.tupleSketch, COMPARISON_TUPLE_SKETCH_K);
		double fastAgmsEstimate = leftSketches.fastAgms.innerProduct(rightSketches.fastAgms);
		double joinSketchEstimate = leftSketches.joinSketch.innerProduct(rightSketches.joinSketch);
		double omniSketchEstimate = leftSketches.omniSketch.innerProduct(rightSketches.omniSketch);
		return new AccuracyResult(truth, exactTupleEstimate, tupleEstimate, fastAgmsEstimate, joinSketchEstimate,
				omniSketchEstimate,
				relativeError(tupleEstimate, truth), relativeError(fastAgmsEstimate, truth),
				relativeError(joinSketchEstimate, truth), relativeError(omniSketchEstimate, truth));
	}

	private static PatternSketches sketchesFor(List<Statement> statements, StatementPattern pattern,
			List<String> keyVars) {
		Map<JoinKey, Long> truth = new HashMap<>();
		ArrayOfDoublesUpdatableSketch tupleSketch = TupleSketchOps.newSketch(COMPARISON_TUPLE_SKETCH_K);
		ArrayOfDoublesUpdatableSketch exactTupleSketch = TupleSketchOps.newSketch(EXACT_TUPLE_SKETCH_K);
		FastAgmsFrequencySketch fastAgms = new FastAgmsFrequencySketch(5, 32, SEED);
		JoinFrequencySketch joinSketch = new JoinFrequencySketch(5, 32, 16, 16, 12L, SEED);
		OmniFrequencySketch omniSketch = new OmniFrequencySketch(5, 32, 64, SEED);
		for (Statement statement : statements) {
			Map<String, Value> bindings = match(pattern, statement);
			if (bindings == null) {
				continue;
			}
			JoinKey logicalKey = joinKey(bindings, keyVars);
			long sketchKey = keyHash(logicalKey);
			truth.merge(logicalKey, 1L, Long::sum);
			TupleSketchOps.update(tupleSketch, sketchKey, 1.0d);
			TupleSketchOps.update(exactTupleSketch, sketchKey, 1.0d);
			fastAgms.update(sketchKey, 1L);
			joinSketch.update(sketchKey, 1L);
			omniSketch.update(sketchKey, 1L);
		}
		return new PatternSketches(truth, tupleSketch, exactTupleSketch, fastAgms, joinSketch, omniSketch);
	}

	private static long exactInnerProduct(Map<JoinKey, Long> left, Map<JoinKey, Long> right) {
		Map<JoinKey, Long> smaller = left.size() <= right.size() ? left : right;
		Map<JoinKey, Long> larger = smaller == left ? right : left;
		long rows = 0L;
		for (Map.Entry<JoinKey, Long> entry : smaller.entrySet()) {
			rows += entry.getValue() * larger.getOrDefault(entry.getKey(), 0L);
		}
		return rows;
	}

	private static long exactMultiProduct(List<Map<JoinKey, Long>> relations) {
		Map<JoinKey, Long> smallest = relations.get(0);
		for (Map<JoinKey, Long> relation : relations) {
			if (relation.size() < smallest.size()) {
				smallest = relation;
			}
		}
		long rows = 0L;
		for (Map.Entry<JoinKey, Long> entry : smallest.entrySet()) {
			long product = entry.getValue();
			boolean matched = true;
			for (Map<JoinKey, Long> relation : relations) {
				if (relation == smallest) {
					continue;
				}
				long multiplicity = relation.getOrDefault(entry.getKey(), 0L);
				if (multiplicity == 0L) {
					matched = false;
					break;
				}
				product *= multiplicity;
			}
			if (matched) {
				rows += product;
			}
		}
		return rows;
	}

	private static double relativeError(double estimate, long truth) {
		return Math.abs(estimate - truth) / Math.max(1.0d, truth);
	}

	private static Map<String, Value> match(StatementPattern pattern, Statement statement) {
		Map<String, Value> bindings = new HashMap<>();
		if (!matchVar(pattern.getSubjectVar(), statement.getSubject(), bindings)) {
			return null;
		}
		if (!matchVar(pattern.getPredicateVar(), statement.getPredicate(), bindings)) {
			return null;
		}
		if (!matchVar(pattern.getObjectVar(), statement.getObject(), bindings)) {
			return null;
		}
		Var contextVar = pattern.getContextVar();
		if (contextVar != null && !matchVar(contextVar, statement.getContext(), bindings)) {
			return null;
		}
		return bindings;
	}

	private static boolean matchVar(Var var, Value value, Map<String, Value> bindings) {
		if (var.hasValue()) {
			return Objects.equals(var.getValue(), value);
		}
		bindings.put(var.getName(), value);
		return true;
	}

	private static JoinKey joinKey(Map<String, Value> bindings, List<String> keyVars) {
		List<Value> values = new ArrayList<>(keyVars.size());
		for (String keyVar : keyVars) {
			values.add(Objects.requireNonNull(bindings.get(keyVar), keyVar));
		}
		return new JoinKey(List.copyOf(values));
	}

	private static long keyHash(JoinKey key) {
		long hash = 0xcbf29ce484222325L;
		for (Value value : key.values()) {
			String stringValue = value.stringValue();
			for (int i = 0; i < stringValue.length(); i++) {
				hash ^= stringValue.charAt(i);
				hash *= 0x100000001b3L;
			}
			hash ^= 0xffL;
			hash *= 0x100000001b3L;
		}
		return hash == Long.MIN_VALUE ? 0L : hash;
	}

	private static List<Statement> skewedSubjectStar(IRI hasEncounter, IRI hasIdentifier) {
		List<Statement> statements = new ArrayList<>();
		for (int i = 0; i < 700; i++) {
			Resource patient = VF.createIRI("urn:join-sketch:patient:" + i);
			int encounterCount = i < 12 ? 80 : 1;
			int identifierCount = i < 12 ? 55 : 1;
			for (int j = 0; j < encounterCount; j++) {
				statements.add(VF.createStatement(patient, hasEncounter,
						VF.createIRI("urn:join-sketch:encounter:" + i + ":" + j)));
			}
			for (int j = 0; j < identifierCount; j++) {
				statements.add(VF.createStatement(patient, hasIdentifier,
						VF.createIRI("urn:join-sketch:identifier:" + i + ":" + j)));
			}
		}
		return statements;
	}

	private static List<Statement> skewedCompositeKeyJoin(IRI prescribedDrug, IRI billedDrug) {
		List<Statement> statements = new ArrayList<>();
		for (int encounterIndex = 0; encounterIndex < 240; encounterIndex++) {
			Resource encounter = VF.createIRI("urn:join-sketch:encounter:" + encounterIndex);
			for (int drugIndex = 0; drugIndex < 8; drugIndex++) {
				Resource drug = VF.createIRI("urn:join-sketch:drug:" + drugIndex);
				int leftContexts = encounterIndex < 20 && drugIndex < 3 ? 28 : 1;
				int rightContexts = encounterIndex < 20 && drugIndex < 3 ? 21 : (drugIndex % 3 == 0 ? 1 : 0);
				for (int contextIndex = 0; contextIndex < leftContexts; contextIndex++) {
					statements.add(VF.createStatement(encounter, prescribedDrug, drug,
							VF.createIRI("urn:join-sketch:left-context:" + contextIndex)));
				}
				for (int contextIndex = 0; contextIndex < rightContexts; contextIndex++) {
					statements.add(VF.createStatement(encounter, billedDrug, drug,
							VF.createIRI("urn:join-sketch:right-context:" + contextIndex)));
				}
			}
		}
		return statements;
	}

	private static List<Statement> skewedThreeWayCompositeKeyJoin(IRI prescribedDrug, IRI billedDrug,
			IRI reconciledDrug) {
		List<Statement> statements = new ArrayList<>();
		for (int encounterIndex = 0; encounterIndex < 160; encounterIndex++) {
			Resource encounter = VF.createIRI("urn:join-sketch:three-way:encounter:" + encounterIndex);
			for (int drugIndex = 0; drugIndex < 6; drugIndex++) {
				Resource drug = VF.createIRI("urn:join-sketch:three-way:drug:" + drugIndex);
				boolean heavy = encounterIndex < 18 && drugIndex < 3;
				int prescribedContexts = heavy ? 12 : 1;
				int billedContexts = heavy ? 9 : (drugIndex % 2 == 0 ? 1 : 0);
				int reconciledContexts = heavy ? 7 : (drugIndex % 3 == 0 ? 1 : 0);
				for (int contextIndex = 0; contextIndex < prescribedContexts; contextIndex++) {
					statements.add(VF.createStatement(encounter, prescribedDrug, drug,
							VF.createIRI("urn:join-sketch:three-way:prescribed-context:" + contextIndex)));
				}
				for (int contextIndex = 0; contextIndex < billedContexts; contextIndex++) {
					statements.add(VF.createStatement(encounter, billedDrug, drug,
							VF.createIRI("urn:join-sketch:three-way:billed-context:" + contextIndex)));
				}
				for (int contextIndex = 0; contextIndex < reconciledContexts; contextIndex++) {
					statements.add(VF.createStatement(encounter, reconciledDrug, drug,
							VF.createIRI("urn:join-sketch:three-way:reconciled-context:" + contextIndex)));
				}
			}
		}
		return statements;
	}

	private static SketchBasedJoinEstimator.Config smallBudgetConfig() {
		return SketchBasedJoinEstimator.Config.defaults()
				.withSketchStrategy(SketchBasedJoinEstimator.SketchStrategy.JOIN_SKETCH)
				.withNominalEntries(16)
				.withSubjectBucketCount(4096)
				.withPredicateBucketCount(64)
				.withObjectBucketCount(4096)
				.withContextBucketCount(16)
				.withEstimateCacheSeconds(0)
				.withThrottleEveryN(1)
				.withThrottleMillis(0)
				.withRefreshSleepMillis(5);
	}

	private static BindingSetAssignment finiteDomainRows(QueryBindingSet... rows) {
		BindingSetAssignment assignment = new BindingSetAssignment();
		assignment.setBindingSets(List.of(rows));
		return assignment;
	}

	private static QueryBindingSet valueRow(String bindingName, Value value) {
		QueryBindingSet row = new QueryBindingSet();
		row.setBinding(bindingName, value);
		return row;
	}

